/**
 * Main consumer setup.
 */
async function startConsumer() {
  let connection;
  let channel;

  try {
    // Connect with TLS in production
    connection = await amqplib.connect(RABBITMQ_URL);
    channel = await connection.createChannel();

    // Set prefetch to process one message at a time
    await channel.prefetch(1);

    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-dead-letter-exchange': '',
        'x-dead-letter-routing-key': `${QUEUE_NAME}.dlq`,
      },
    });

    // Dead letter queue for failed messages
    await channel.assertQueue(`${QUEUE_NAME}.dlq`, { durable: true });

    console.log(`[*] Waiting for payment events in queue: ${QUEUE_NAME}`);
    console.log('[*] Message signature verification: ENABLED');
    console.log('[*] Idempotency checking: ENABLED');
    console.log('[*] Input validation: ENABLED');

    channel.consume(QUEUE_NAME, async (msg) => {
      if (!msg) return;

      const rawContent = msg.content.toString();
      const signature = msg.properties.headers?.signature;
      const correlationId = msg.properties.correlationId || 'unknown';

      console.log(`\n--- Received message (correlationId: ${correlationId}) ---`);

      try {
        // STEP 1: Verify message signature
        if (!verifyMessageSignature(rawContent, signature)) {
          console.error(`SECURITY: Message signature verification FAILED (correlationId: ${correlationId})`);
          // Reject without requeue - send to DLQ for investigation
          channel.nack(msg, false, false);
          return;
        }
        console.log('✓ Signature verified');

        // STEP 2: Parse JSON safely
        let payment;
        try {
          payment = JSON.parse(rawContent);
        } catch (parseError) {
          console.error(`Invalid JSON in message: ${parseError.message}`);
          channel.nack(msg, false, false);
          return;
        }

        // STEP 3: Validate message structure and content
        const validation = validatePaymentMessage(payment);
        if (!validation.valid) {
          console.error(`Validation failed: ${validation.errors.join(', ')}`);
          channel.nack(msg, false, false);
          return;
        }
        console.log('✓ Validation passed');

        // STEP 4: Idempotency check
        if (idempotencyStore.has(payment.messageId)) {
          console.warn(`Duplicate message detected: ${payment.messageId} - skipping`);
          channel.ack(msg);
          return;
        }
        console.log('✓ Idempotency check passed');

        // STEP 5: Process the payment event
        const result = await processPaymentEvent(payment);

        // Mark as processed for idempotency
        idempotencyStore.add(payment.messageId);

        console.log(`✓ Successfully processed: ${result.eventType} for ${result.paymentId}`);
        channel.ack(msg);

      } catch (error) {
        console.error(`Error processing message: ${error.message}`);

        // Check retry count
        const retryCount = (msg.properties.headers?.['x-retry-count'] || 0);
        const maxRetries = 3;

        if (retryCount < maxRetries) {
          console.log(`Retrying (${retryCount + 1}/${maxRetries})...`);
          // Republish with incremented retry count
          channel.publish('', QUEUE_NAME, msg.content, {
            ...msg.properties,
            headers: {
              ...msg.properties.headers,
              'x-retry-count': retryCount + 1,
            },
          });
          channel.ack(msg);
        } else {
          console.error(`Max retries exceeded. Sending to DLQ.`);
          channel.nack(msg, false, false);
        }
      }
    });

    // Graceful shutdown
    const shutdown = async (signal) => {
      console.log(`\n${signal} received. Shutting down gracefully...`);
      try {
        await channel.close();
        await connection.close();
      } catch (err) {
        console.error('Error during shutdown:', err.message);
      }
      process.exit(0);
    };

    process.on('SIGINT', () => shutdown('SIGINT'));
    process.on('SIGTERM', () => shutdown('SIGTERM'));

    connection.on('error', (err) => {
      console.error('Connection error:', err.message);
    });

    connection.on('close', () => {
      console.error('Connection closed. Attempting reconnect in 5s...');
      setTimeout(startConsumer, 5000);
    });

  } catch (error) {
    console.error('Failed to start consumer:', error.message);
    setTimeout(startConsumer, 5000);
  }
}

// --- Helper: Example publisher for testing (shows how to sign messages) ---
async function publishTestMessage() {
  const connection = await amqplib.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  const payment = {
    messageId: crypto.randomUUID(),
    eventType: 'payment.created',
    paymentId: `pay-${crypto.randomUUID()}`,
    amount: 49.99,
    currency: 'USD',
    customerId: 'cust-12345',
    timestamp: new Date().toISOString(),
  };

  const messageBody = JSON.stringify(payment);
  const signature = crypto
    .createHmac('sha256', HMAC_SECRET)
    .update(messageBody)
    .digest('hex');

  channel.sendToQueue(QUEUE_NAME, Buffer.from(messageBody), {
    persistent: true,
    correlationId: crypto.randomUUID(),
    contentType: 'application/json',
    headers: { signature },
  });

  console.log('Test message published:', payment.paymentId);
  await channel.close();
  await connection.close();
}

// Start the consumer
startConsumer().catch(console.error);

